import operator
import tkinter as tk
from tkinter import ttk


OPS = {
    ast.Add: operator.add,
    ast.Sub: operator.sub,
    ast.Mult: operator.mul,
    ast.Div: operator.truediv,
    ast.USub: operator.neg,
}


def safe_eval(expression):
    expression = expression.replace("x", "*").replace("X", "*").replace(",", ".")
    node = ast.parse(expression, mode="eval").body

    def visit(item):
        if isinstance(item, ast.Constant) and isinstance(item.value, (int, float)):
            return item.value
        if isinstance(item, ast.BinOp) and type(item.op) in OPS:
            return OPS[type(item.op)](visit(item.left), visit(item.right))
        if isinstance(item, ast.UnaryOp) and type(item.op) in OPS:
            return OPS[type(item.op)](visit(item.operand))
        raise ValueError("Gecersiz ifade")

    result = visit(node)
    if isinstance(result, float) and result.is_integer():
        return str(int(result))
    if isinstance(result, float):
        return f"{result:.10f}".rstrip("0").rstrip(".")
    return str(result)


class CalculatorApp(tk.Tk):
    def __init__(self):
        super().__init__()
        self.title("Hesap Makinesi")
        self.geometry("360x520")
        self.minsize(320, 460)
        self.configure(bg="#10141f")
        self.expression = tk.StringVar(value="")
        self._build_ui()

    def _build_ui(self):
        style = ttk.Style(self)
        style.theme_use("clam")
        style.configure("Display.TEntry", fieldbackground="#171d2b", foreground="#f8fafc", borderwidth=0, padding=14)

        frame = tk.Frame(self, bg="#10141f", padx=16, pady=16)
        frame.pack(fill="both", expand=True)

        display = ttk.Entry(frame, textvariable=self.expression, justify="right", font=("Segoe UI", 22), style="Display.TEntry")
        display.grid(row=0, column=0, columnspan=4, sticky="nsew", pady=(0, 16), ipady=10)
        display.focus_set()

        buttons = [
            ("C", 1, 0), ("DEL", 1, 1), ("(", 1, 2), (")", 1, 3),
            ("7", 2, 0), ("8", 2, 1), ("9", 2, 2), ("/", 2, 3),
            ("4", 3, 0), ("5", 3, 1), ("6", 3, 2), ("x", 3, 3),
            ("1", 4, 0), ("2", 4, 1), ("3", 4, 2), ("-", 4, 3),
            ("0", 5, 0), (".", 5, 1), ("=", 5, 2), ("+", 5, 3),
        ]

        for label, row, column in buttons:
            button = tk.Button(
                frame,
                text=label,
                command=lambda value=label: self.press(value),
                font=("Segoe UI", 16, "bold"),
                fg="#f8fafc",
                bg="#232b3d" if label not in {"+", "-", "x", "/", "="} else "#7c5cff",
                activebackground="#20d6a5",
                activeforeground="#071018",
                relief="flat",
                bd=0,
            )
            button.grid(row=row, column=column, sticky="nsew", padx=5, pady=5, ipady=12)

        for index in range(4):
            frame.columnconfigure(index, weight=1)
        for index in range(6):
            frame.rowconfigure(index, weight=1)

        self.bind("<Return>", lambda _event: self.press("="))
        self.bind("<BackSpace>", lambda _event: self.press("DEL"))
        self.bind("<Escape>", lambda _event: self.press("C"))
        self.bind("<Key>", self._handle_key)

    def _handle_key(self, event):
        if event.char in "0123456789.+-*/()":
            self.press(event.char)

    def press(self, value):
        current = self.expression.get()
        if value == "C":
            self.expression.set("")
        elif value == "DEL":
            self.expression.set(current[:-1])
        elif value == "=":
            try:
                self.expression.set(safe_eval(current))
            except Exception:
                self.expression.set("Error")
        else:
            if current == "Error":
                current = ""
            self.expression.set(current + value)


if __name__ == "__main__":
    CalculatorApp().mainloop()
